// 定义一个公共的标签属性，每个成员都有，但值不同
interface Circle {
  kind: 'circle'
  radius: number
}

interface Square {
  kind: 'square'
  sideLength: number
}

interface Triangle {
  kind: 'triangle'
  base: number
  height: number
}

// 联合类型
type Shape = Circle | Square | Triangle

// 通过 kind 字段进行类型收窄
function getArea(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      // shape 被收窄为 Circle
      return Math.PI * shape.radius ** 2
    case 'square':
      // shape 被收窄为 Square
      return shape.sideLength ** 2
    case 'triangle':
      // shape 被收窄为 Triangle
      return (shape.base * shape.height) / 2
  }
}

// 也可以用在函数重载或条件类型里
function describe(shape: Shape): string {
  if (shape.kind === 'circle') {
    return `圆，半径 ${shape.radius}`
  }
  if (shape.kind === 'square') {
    return `正方形，边长 ${shape.sideLength}`
  }
  return `三角形，底 ${shape.base} 高 ${shape.height}`
}
```

关键点：`kind` 这个属性就是**可辨识标签**，它的类型是字面量类型（`'circle'`、`'square'` 等）。TypeScript 编译器会跟踪这个字段的值，在分支里自动把联合类型收窄到对应的具体接口，让你能安全访问该分支独有的属性。

